define("local_coursetags/coursetags",["core/ajax","core/templates"],(function(Ajax,Templates){
"use strict";
const SELECTORS={BOOST_UNION:'[data-region="course-content"][data-course-id]',STANDARD:'.coursebox[data-courseid]'};
const getTarget=el=>{const c=el.querySelector('.course-info-container');if(c)return{element:c,position:'beforeend'};const n=el.querySelector('.aalink.coursename');if(n)return{element:n,position:'afterend'};const s=el.querySelector('.content .summary');if(s)return{element:s,position:'afterend'};return{element:el,position:'beforeend'}};
let courseElements=new Map();
const activeTags=new Set(),courseTagMap=new Map(),tagIndex=new Map();
const filterCourses=()=>{courseElements.forEach((el,cid)=>{if(!activeTags.size){el.style.display='';return;}const t=courseTagMap.get(cid)??new Set();el.style.display=[...activeTags].every(k=>t.has(k))?'':'none';})};
const addActiveTag=(rawname,ac)=>{const key=rawname.toLowerCase();if(activeTags.has(key))return;activeTags.add(key);const chip=document.createElement('span');chip.className='local-coursetags-filter-chip badge rounded-pill';chip.dataset.tagKey=key;chip.appendChild(document.createTextNode(rawname+' '));const btn=document.createElement('button');btn.type='button';btn.className='local-coursetags-filter-remove';btn.setAttribute('aria-label','Remove filter: '+rawname);btn.textContent='×';btn.addEventListener('click',()=>{activeTags.delete(key);chip.remove();filterCourses();ac.hidden=activeTags.size===0;});chip.appendChild(btn);ac.appendChild(chip);ac.hidden=false;filterCourses();};
const init=async()=>{
document.querySelectorAll(SELECTORS.BOOST_UNION).forEach(el=>{const id=parseInt(el.dataset.courseId,10);if(id)courseElements.set(id,el)});
document.querySelectorAll(SELECTORS.STANDARD).forEach(el=>{const id=parseInt(el.dataset.courseid,10);if(id&&!courseElements.has(id))courseElements.set(id,el)});
if(!courseElements.size)return;
let results;
try{results=await Ajax.call([{methodname:'local_coursetags_get_course_tags',args:{courseids:[...courseElements.keys()]}}])[0]}catch(e){window.console?.warn('local_coursetags: AJAX error',e);return}
for(const d of results){if(!d.tags?.length)continue;const ts=new Set();for(const t of d.tags){const k=t.rawname.toLowerCase();ts.add(k);if(!tagIndex.has(k))tagIndex.set(k,t.rawname);}courseTagMap.set(d.courseid,ts);}
for(const d of results){if(!d.tags?.length)continue;const el=courseElements.get(d.courseid);if(!el)continue;try{const{html}=await Templates.renderForPromise('local_coursetags/coursetags',{tags:d.tags});const{element:tgt,position:p}=getTarget(el);tgt.insertAdjacentHTML(p,html)}catch(e){window.console?.warn('local_coursetags: render error',d.courseid,e)}}
if(!tagIndex.size)return;
let inputWrap;
try{const{html}=await Templates.renderForPromise('local_coursetags/filterbar',{});const wrap=document.createElement('div');wrap.innerHTML=html;inputWrap=wrap.firstElementChild;}catch(e){window.console?.warn('local_coursetags: filterbar render error',e);return}
const ac=document.createElement('div');ac.className='local-coursetags-active';ac.setAttribute('aria-live','polite');ac.hidden=true;
const actionBar=document.querySelector('#action_bar');const flexRow=actionBar?.querySelector('.d-flex');
if(flexRow){flexRow.appendChild(inputWrap);actionBar.appendChild(ac);}else{const firstEl=[...courseElements.values()][0];const fb=document.createElement('div');fb.className='local-coursetags-filterbar';fb.appendChild(inputWrap);fb.appendChild(ac);firstEl.parentElement.insertBefore(fb,firstEl);}
const input=inputWrap.querySelector('.local-coursetags-input');const suggestions=inputWrap.querySelector('.local-coursetags-suggestions');
const allTagNames=[...tagIndex.entries()].sort((a,b)=>a[0].localeCompare(b[0]));
let hi=-1;
const showSugg=matches=>{suggestions.innerHTML='';hi=-1;if(!matches.length){suggestions.hidden=true;return;}matches.forEach(([k,r])=>{const li=document.createElement('li');li.dataset.key=k;li.textContent=r;li.setAttribute('role','option');suggestions.appendChild(li);});suggestions.hidden=false;};
const selSugg=li=>{if(!li)return;const r=tagIndex.get(li.dataset.key);if(r)addActiveTag(r,ac);input.value='';suggestions.hidden=true;hi=-1;input.focus();};
input.addEventListener('input',()=>{const q=input.value.trim().toLowerCase();if(!q){suggestions.hidden=true;return;}showSugg(allTagNames.filter(([k])=>k.includes(q)).slice(0,8));});
input.addEventListener('keydown',e=>{const items=[...suggestions.querySelectorAll('li')];if(e.key==='ArrowDown'){e.preventDefault();hi=Math.min(hi+1,items.length-1);items.forEach((li,i)=>li.classList.toggle('active',i===hi));}else if(e.key==='ArrowUp'){e.preventDefault();hi=Math.max(hi-1,-1);items.forEach((li,i)=>li.classList.toggle('active',i===hi));}else if(e.key==='Enter'){e.preventDefault();selSugg(hi>=0?items[hi]:items[0]);}else if(e.key==='Escape'){suggestions.hidden=true;hi=-1;}});
input.addEventListener('blur',()=>{setTimeout(()=>{suggestions.hidden=true;hi=-1;},150);});
suggestions.addEventListener('mousedown',e=>{const li=e.target.closest('li');if(li){e.preventDefault();selSugg(li);}});
document.addEventListener('click',e=>{const badge=e.target.closest('.local-coursetags-badge');if(!badge)return;e.preventDefault();const r=badge.title||badge.textContent.trim();if(r)addActiveTag(r,ac);});
};
return{init};
}));
